import { useEffect, useState } from 'react'
import {
  fetchMyNotifications,
  fetchUnreadCount,
  markNotificationRead,
  markAllNotificationsRead,
  type NotificationDto,
} from '../api/notifications'
import { getAccessToken } from '../lib/authStorage'

const POLL_INTERVAL_MS = 60_000

export default function NotificationBell() {
  const [open, setOpen] = useState(false)
  const [unread, setUnread] = useState(0)
  const [items, setItems] = useState<NotificationDto[]>([])
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!getAccessToken()) return
    let alive = true
    const tick = () => {
      fetchUnreadCount()
        .then((r) => { if (alive) setUnread(r.count) })
        .catch(() => { /* silent */ })
    }
    tick()
    const id = setInterval(tick, POLL_INTERVAL_MS)
    return () => { alive = false; clearInterval(id) }
  }, [])

  useEffect(() => {
    if (!open) return
    setLoading(true)
    fetchMyNotifications()
      .then((all) => setItems(all.slice(0, 12)))
      .catch(() => { /* silent */ })
      .finally(() => setLoading(false))
  }, [open])

  function onClickItem(n: NotificationDto) {
    if (n.read) return
    void markNotificationRead(n.id)
    setItems((prev) => prev.map((x) => x.id === n.id ? { ...x, read: true } : x))
    setUnread((c) => Math.max(0, c - 1))
  }

  function onMarkAll() {
    void markAllNotificationsRead()
    setItems((prev) => prev.map((x) => ({ ...x, read: true })))
    setUnread(0)
  }

  if (!getAccessToken()) return null

  return (
    <div style={{ position: 'relative' }}>
      <button
        onClick={() => setOpen((v) => !v)}
        aria-label={`Уведомления${unread > 0 ? ` (${unread} непрочитанных)` : ''}`}
        style={{
          position: 'relative',
          background: 'none', border: 'none', cursor: 'pointer',
          padding: 6, borderRadius: 8, fontSize: 20, lineHeight: 1,
        }}
      >
        🔔
        {unread > 0 && (
          <span
            aria-hidden
            style={{
              position: 'absolute', top: 2, right: 2,
              minWidth: 16, height: 16, padding: '0 4px',
              background: '#dc2626', color: '#fff', borderRadius: 8,
              fontSize: 10, fontWeight: 800,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}
          >
            {unread > 99 ? '99+' : unread}
          </span>
        )}
      </button>

      {open && (
        <>
          <div
            onClick={() => setOpen(false)}
            style={{ position: 'fixed', inset: 0, zIndex: 998 }}
          />
          <div
            style={{
              position: 'absolute', top: 'calc(100% + 8px)', right: 0, zIndex: 999,
              width: 360, maxWidth: 'calc(100vw - 24px)',
              background: 'var(--paper)', borderRadius: 14,
              border: '1.5px solid var(--paper-3, #e5e2f0)',
              boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
              maxHeight: 480, overflowY: 'auto',
            }}
          >
            <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 16px', borderBottom: '1px solid var(--paper-3, #e5e2f0)' }}>
              <strong style={{ fontSize: 14 }}>Уведомления</strong>
              {unread > 0 && (
                <button
                  onClick={onMarkAll}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--violet)', fontSize: 12, fontWeight: 700 }}
                >
                  Прочитать все
                </button>
              )}
            </header>

            {loading ? (
              <div style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)', fontSize: 13 }}>Загрузка…</div>
            ) : items.length === 0 ? (
              <div style={{ padding: 32, textAlign: 'center', color: 'var(--ink-soft)', fontSize: 13 }}>Уведомлений пока нет</div>
            ) : (
              <ul style={{ listStyle: 'none', margin: 0, padding: 0 }}>
                {items.map((n) => (
                  <li
                    key={n.id}
                    onClick={() => onClickItem(n)}
                    style={{
                      padding: '10px 16px',
                      borderBottom: '1px solid var(--paper-3, #e5e2f0)',
                      background: n.read ? 'transparent' : 'var(--violet-soft, #f0edff)',
                      cursor: n.read ? 'default' : 'pointer',
                    }}
                  >
                    <div style={{ fontWeight: n.read ? 500 : 700, fontSize: 13 }}>{n.title}</div>
                    <div style={{ fontSize: 12, color: 'var(--ink-soft)', marginTop: 2 }}>{n.body}</div>
                    <div style={{ fontSize: 10, color: 'var(--ink-soft)', marginTop: 4 }}>
                      {new Date(n.createdAt).toLocaleString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
                    </div>
                  </li>
                ))}
              </ul>
            )}
          </div>
        </>
      )}
    </div>
  )
}
